import{CLASS_STATS,DIFFICULTY_MODS,WEAPON_DEFINITIONS,BATTLEBACKGROUNDS,PLAYER_SKINS}from"./game-state.js";const CONFIG_KEY="coliseo_v3_config";const SKIN_CHARACTER_NAMES={classic:"Uthred",valor:"Uthred",sombra:"Uthred",berserker:"Shrek",mistico:"Yoda",diplomatico:"Leia",comico:"Jar Jar",once:"Once","místico":"Yoda","diplomático":"Leia","cómico":"Jar Jar"};export function getCharacterNameForSkin(skinId){return SKIN_CHARACTER_NAMES[skinId]||"Uthred"}export function loadPlayerConfig(state,roguelikeModeRef){try{const saved=JSON.parse(localStorage.getItem(CONFIG_KEY))||{};state.applyPlayerConfig({playerName:saved.playerName||state.playerName,playerClass:saved.playerClass&&CLASS_STATS[saved.playerClass]?saved.playerClass:state.playerClass,playerWeapon:saved.playerWeapon&&WEAPON_DEFINITIONS[saved.playerWeapon]?saved.playerWeapon:state.playerWeapon,playerSkin:saved.playerSkin&&PLAYER_SKINS[saved.playerSkin]?saved.playerSkin:state.playerSkin,battleBackground:saved.battleBackground&&BATTLEBACKGROUNDS[saved.battleBackground]?saved.battleBackground:state.battleBackground,difficulty:saved.difficulty&&DIFFICULTY_MODS[saved.difficulty]?saved.difficulty:state.difficulty});if(typeof saved.roguelikeMode==="boolean"){roguelikeModeRef.set(saved.roguelikeMode)}return saved}catch(e){return{}}}export function savePlayerConfig(state,getPlayerName,getRoguelikeMode){try{const config=state.getPlayerConfig();localStorage.setItem(CONFIG_KEY,JSON.stringify({...config,playerName:getPlayerName()||config.playerName||"",roguelikeMode:getRoguelikeMode()}))}catch(e){}}export function selectClass(state,cls,getById,saveConfig){state.playerClass=cls;document.querySelectorAll(".class-btn").forEach(b=>b.classList.toggle("selected",b.dataset.class===cls));const s=CLASS_STATS[cls];const preview=getById("class-preview");if(preview)preview.innerHTML=`<span>${s.icon}</span> <strong>${cls.toUpperCase()}</strong>: ${s.desc}`;saveConfig()}export function selectDifficulty(state,diff,saveConfig){state.difficulty=diff;document.querySelectorAll(".diff-btn").forEach(b=>b.classList.toggle("selected",b.dataset.diff===diff));saveConfig()}export function selectWeapon(state,weaponId,getById,saveConfig){state.playerWeapon=weaponId;document.querySelectorAll(".weapon-card").forEach(card=>card.classList.toggle("selected",card.dataset.weapon===weaponId));const weaponInfo=WEAPON_DEFINITIONS[weaponId];const preview=getById("weapon-preview");if(preview&&weaponInfo){preview.textContent=`${weaponInfo.icon} ${weaponInfo.name}: ${weaponInfo.description}`}saveConfig()}export function selectBackground(state,backgroundId,getById,saveConfig){state.battleBackground=backgroundId;const backgroundSelect=getById("background-options");if(backgroundSelect)backgroundSelect.value=backgroundId;const preview=getById("background-preview");const bgInfo=BATTLEBACKGROUNDS[backgroundId];if(preview&&bgInfo){preview.textContent=`${bgInfo.label} - ${bgInfo.description}`}saveConfig()}export function selectSkin(state,skinId,getById,uiRenderer,saveConfig){const previousDefaultName=getCharacterNameForSkin(state.playerSkin);state.playerSkin=skinId;const skinSelect=getById("skin-options");if(skinSelect)skinSelect.value=skinId;const nameInput=getById("player-name");const nextDefaultName=getCharacterNameForSkin(skinId);if(nameInput){const currentValue=nameInput.value.trim();if(!currentValue||currentValue===previousDefaultName||currentValue==="Uthred"){nameInput.value=nextDefaultName}}const preview=getById("skin-preview");const previewCharacter=getById("skin-preview-character");const skinInfo=PLAYER_SKINS[skinId];if(preview&&skinInfo){preview.textContent=`${skinInfo.label} - ${skinInfo.description}`}if(previewCharacter){previewCharacter.textContent=`Personaje: ${nextDefaultName}`}uiRenderer.updatePlayerSkin(state);saveConfig()}export function renderSkinOptions(state,getById){const skinContainer=getById("skin-options");if(!skinContainer)return;skinContainer.innerHTML="";Object.entries(PLAYER_SKINS).forEach(([id,skin])=>{const option=document.createElement("option");option.value=id;option.textContent=skin.label;skinContainer.appendChild(option)});skinContainer.value=state.playerSkin}export function renderSelectionOptions(state,getById,onSelectWeapon){const weaponContainer=getById("weapon-options");const bgContainer=getById("background-options");if(weaponContainer){weaponContainer.innerHTML="";Object.entries(WEAPON_DEFINITIONS).forEach(([id,weapon])=>{const card=document.createElement("button");card.type="button";card.className=`option-card weapon-card${state.playerWeapon===id?" selected":""}`;card.dataset.weapon=id;card.innerHTML=`\n        <div class="option-icon">${weapon.icon}</div>\n        <div class="option-title">${weapon.name}</div>\n        <div class="option-desc">${weapon.description}</div>\n      `;card.addEventListener("click",()=>onSelectWeapon(id));weaponContainer.appendChild(card)})}if(bgContainer){bgContainer.innerHTML="";Object.entries(BATTLEBACKGROUNDS).forEach(([id,bg])=>{const option=document.createElement("option");option.value=id;option.textContent=bg.label;bgContainer.appendChild(option)});bgContainer.value=state.battleBackground}}